1	// Package config defines the govirt configuration schema and its loading,
2	// default-application, validation, and persistence logic.
3	//
4	// A config has two kinds of sections: input sections (vm, dns) written by the
5	// user and never modified by govirt, and state sections (local, aws, do)
6	// managed automatically by the providers.
7	package config
8	
9	import (
10		"fmt"
11		"regexp"
12	)
13	
14	// Config is the top-level config.json structure.
15	type Config struct {
16		VM    *VMConfig   `json:"vm,omitempty"`
17		DNS   *DNSConfig  `json:"dns,omitempty"`
18		Local *LocalState `json:"local,omitempty"`
19		AWS   *AWSState   `json:"aws,omitempty"`
20		DO    *DOState    `json:"do,omitempty"`
21	}
22	
23	// VMConfig is the user-authored vm input section.
24	type VMConfig struct {
25		Name         string  `json:"name"`
26		Users        []User  `json:"users,omitempty"`
27		CPUs         int     `json:"cpus,omitempty"`
28		Memory       string  `json:"memory,omitempty"`
29		Disk         string  `json:"disk,omitempty"`
30		Image        string  `json:"image,omitempty"`
31		Mounts       []Mount `json:"mounts,omitempty"`
32		InstanceType string  `json:"instance_type,omitempty"`
33		OS           string  `json:"os,omitempty"`
34		Region       string  `json:"region,omitempty"`
35		VpcID        string  `json:"vpc_id,omitempty"`
36		SubnetID     string  `json:"subnet_id,omitempty"`
37		DOSize       string  `json:"do_size,omitempty"`
38		DORegion     string  `json:"do_region,omitempty"`
39		DOImage      string  `json:"do_image,omitempty"`
40		DOVpcID      string  `json:"do_vpc_id,omitempty"`
41		SSHCidr      string  `json:"ssh_cidr,omitempty"`
42		WebCidr      string  `json:"web_cidr,omitempty"`
43	}
44	
45	// DNSConfig is the user-authored dns input section.
46	type DNSConfig struct {
47		Hostname     string   `json:"hostname,omitempty"`
48		Domain       string   `json:"domain,omitempty"`
49		TTL          int      `json:"ttl,omitempty"`
50		IsApexDomain bool     `json:"is_apex_domain,omitempty"`
51		CNAMEAliases []string `json:"cname_aliases,omitempty"`
52		ZoneID       string   `json:"zone_id,omitempty"`
53	}
54	
55	// LocalState is the govirt-managed state for a local libvirt VM.
56	type LocalState struct {
57		IP           string `json:"ip,omitempty"`
58		HostsEntry   bool   `json:"hosts_entry,omitempty"`
59		DomainName   string `json:"domain_name,omitempty"`
60		DiskPath     string `json:"disk_path,omitempty"`
61		CloudInitISO string `json:"cloud_init_iso,omitempty"`
62		Network      string `json:"network,omitempty"`
63	}
64	
65	// AWSState is the govirt-managed state for an AWS deployment.
66	type AWSState struct {
67		PublicIP              string      `json:"public_ip,omitempty"`
68		InstanceID            string      `json:"instance_id,omitempty"`
69		StackID               string      `json:"stack_id,omitempty"`
70		StackName             string      `json:"stack_name,omitempty"`
71		SecurityGroup         string      `json:"security_group,omitempty"`
72		AMIID                 string      `json:"ami_id,omitempty"`
73		VpcID                 string      `json:"vpc_id,omitempty"`
74		SubnetID              string      `json:"subnet_id,omitempty"`
75		CreatedVPC            bool        `json:"created_vpc,omitempty"`
76		CreatedSubnet         bool        `json:"created_subnet,omitempty"`
77		InternetGatewayID     string      `json:"internet_gateway_id,omitempty"`
78		RouteTableID          string      `json:"route_table_id,omitempty"`
79		RouteTableAssociation string      `json:"route_table_association_id,omitempty"`
80		ZoneID                string      `json:"zone_id,omitempty"`
81		FQDN                  string      `json:"fqdn,omitempty"`
82		DNSRecords            []DNSRecord `json:"dns_records,omitempty"`
83	}
84	
85	// DOState is the govirt-managed state for a DigitalOcean deployment.
86	type DOState struct {
87		DropletID  int        `json:"droplet_id,omitempty"`
88		PublicIP   string     `json:"public_ip,omitempty"`
89		FQDN       string     `json:"fqdn,omitempty"`
90		FirewallID string     `json:"firewall_id,omitempty"`
91		DNSRecords []DORecord `json:"dns_records,omitempty"`
92	}
93	
94	// User maps a VM account to a GitHub account used for SSH key lookup.
95	type User struct {
96		Username       string `json:"username"`
97		GitHubUsername string `json:"github_username"`
98	}
99	
100	// Mount is a host directory shared into a local VM.
101	type Mount struct {
102		Source string `json:"source"`
103		Target string `json:"target"`
104	}
105	
106	// DNSRecord tracks a Route53 record so it can be deleted on destroy.
107	type DNSRecord struct {
108		Name string `json:"name"`
109		Type string `json:"type"`
110	}
111	
112	// DORecord tracks a DigitalOcean DNS record (with its numeric ID) for deletion.
113	type DORecord struct {
114		ID   int    `json:"id"`
115		Name string `json:"name"`
116		Type string `json:"type"`
117	}
118	
119	// Defaults applied by ApplyDefaults.
120	const (
121		DefaultCPUs         = 2
122		DefaultMemory       = "2G"
123		DefaultDisk         = "20G"
124		DefaultImage        = "24.04"
125		DefaultRegion       = "us-east-1"
126		DefaultInstanceType = "t3.micro"
127		DefaultOS           = "ubuntu-24.04"
128		DefaultTTL          = 300
129	)
130	
131	var (
132		usernameRE = regexp.MustCompile(`^[a-z][a-z0-9_-]*$`)
133		githubRE   = regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9-]*$`)
134	)
135	
136	// ApplyDefaults fills unset input fields with their documented defaults.
137	// It does not touch state sections.
138	func (c *Config) ApplyDefaults() {
139		if c.VM == nil {
140			return
141		}
142		vm := c.VM
143		if vm.CPUs == 0 {
144			vm.CPUs = DefaultCPUs
145		}
146		if vm.Memory == "" {
147			vm.Memory = DefaultMemory
148		}
149		if vm.Disk == "" {
150			vm.Disk = DefaultDisk
151		}
152		if vm.Image == "" {
153			vm.Image = DefaultImage
154		}
155		if vm.Region == "" {
156			vm.Region = DefaultRegion
157		}
158		if vm.InstanceType == "" {
159			vm.InstanceType = DefaultInstanceType
160		}
161		if vm.OS == "" {
162			vm.OS = DefaultOS
163		}
164		if c.DNS != nil {
165			if c.DNS.TTL == 0 {
166				c.DNS.TTL = DefaultTTL
167			}
168			if c.DNS.Hostname == "" {
169				c.DNS.Hostname = vm.Name
170			}
171		}
172	}
173	
174	// Validate enforces the documented validation rules on the input sections.
175	func (c *Config) Validate() error {
176		if c.VM == nil {
177			return fmt.Errorf("config missing required 'vm' section")
178		}
179		if c.VM.Name == "" {
180			return fmt.Errorf("vm.name is required")
181		}
182		if len(c.VM.Users) == 0 {
183			return fmt.Errorf("vm.users must have at least one entry")
184		}
185		seen := make(map[string]bool, len(c.VM.Users))
186		for i, u := range c.VM.Users {
187			if !usernameRE.MatchString(u.Username) {
188				return fmt.Errorf("vm.users[%d].username %q is invalid: must match ^[a-z][a-z0-9_-]*$", i, u.Username)
189			}
190			if !githubRE.MatchString(u.GitHubUsername) {
191				return fmt.Errorf("vm.users[%d].github_username %q is invalid: must match ^[a-zA-Z0-9][a-zA-Z0-9-]*$", i, u.GitHubUsername)
192			}
193			if seen[u.Username] {
194				return fmt.Errorf("duplicate username %q in vm.users", u.Username)
195			}
196			seen[u.Username] = true
197		}
198		if c.DNS != nil {
199			if len(c.DNS.CNAMEAliases) > 0 && c.DNS.Domain == "" {
200				return fmt.Errorf("dns.cname_aliases requires dns.domain")
201			}
202			if c.DNS.IsApexDomain && c.DNS.Domain == "" {
203				return fmt.Errorf("dns.is_apex_domain requires dns.domain")
204			}
205		}
206		return nil
207	}
208	
209	// ValidateName reports whether a VM name is safe to pass to shell-out tooling.
210	// It reuses the username grammar, which excludes shell metacharacters.
211	func ValidateName(name string) error {
212		if !usernameRE.MatchString(name) {
213			return fmt.Errorf("invalid VM name %q: must match ^[a-z][a-z0-9_-]*$", name)
214		}
215		return nil
216	}
