1	package config
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os"
7		"path/filepath"
8	)
9	
10	// ConfigFileName is the per-stack config file name.
11	const ConfigFileName = "config.json"
12	
13	// CloudInitFileName is the per-stack cloud-init template file name.
14	const CloudInitFileName = "cloud-init.yaml"
15	
16	// StackDir returns the directory for a named stack under the base folder.
17	func StackDir(baseFolder, name string) string {
18		return filepath.Join(baseFolder, name)
19	}
20	
21	// ConfigPath returns the config.json path for a named stack.
22	func ConfigPath(baseFolder, name string) string {
23		return filepath.Join(baseFolder, name, ConfigFileName)
24	}
25	
26	// CloudInitPath returns the cloud-init.yaml path for a named stack.
27	func CloudInitPath(baseFolder, name string) string {
28		return filepath.Join(baseFolder, name, CloudInitFileName)
29	}
30	
31	// Load reads, parses, and default-applies a config.json at path.
32	// It does not validate; callers decide when validation is required (e.g. create).
33	func Load(path string) (*Config, error) {
34		data, err := os.ReadFile(path)
35		if err != nil {
36			if os.IsNotExist(err) {
37				return nil, fmt.Errorf("config file not found: create %s", path)
38			}
39			return nil, fmt.Errorf("reading config %s: %w", path, err)
40		}
41		var cfg Config
42		if err := json.Unmarshal(data, &cfg); err != nil {
43			return nil, fmt.Errorf("parsing config %s: %w", path, err)
44		}
45		cfg.ApplyDefaults()
46		return &cfg, nil
47	}
48	
49	// Save writes the config back to path as indented JSON, preserving input
50	// sections and persisting state sections. The parent directory is created if
51	// needed.
52	func Save(path string, cfg *Config) error {
53		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
54			return fmt.Errorf("creating stack dir: %w", err)
55		}
56		data, err := json.MarshalIndent(cfg, "", "  ")
57		if err != nil {
58			return fmt.Errorf("encoding config: %w", err)
59		}
60		data = append(data, '\n')
61		if err := os.WriteFile(path, data, 0o644); err != nil {
62			return fmt.Errorf("writing config %s: %w", path, err)
63		}
64		return nil
65	}
