1	package libvirt
2	
3	import (
4		"bytes"
5		"context"
6		"fmt"
7		"os/exec"
8		"strings"
9	)
10	
11	// Runner executes external commands. It is an interface so tests can supply
12	// canned output without invoking real binaries.
13	type Runner interface {
14		// Run executes a command, discarding stdout.
15		Run(ctx context.Context, name string, args ...string) error
16		// Output executes a command and returns its combined stdout.
17		Output(ctx context.Context, name string, args ...string) ([]byte, error)
18	}
19	
20	// execRunner runs commands via os/exec. Arguments are passed as an explicit
21	// slice (no shell), preventing command injection.
22	type execRunner struct{}
23	
24	func (execRunner) Run(ctx context.Context, name string, args ...string) error {
25		cmd := exec.CommandContext(ctx, name, args...)
26		var stderr bytes.Buffer
27		cmd.Stderr = &stderr
28		if err := cmd.Run(); err != nil {
29			msg := strings.TrimSpace(stderr.String())
30			if msg != "" {
31				return fmt.Errorf("%s %s: %s: %w", name, strings.Join(args, " "), msg, err)
32			}
33			return fmt.Errorf("%s %s: %w", name, strings.Join(args, " "), err)
34		}
35		return nil
36	}
37	
38	func (execRunner) Output(ctx context.Context, name string, args ...string) ([]byte, error) {
39		cmd := exec.CommandContext(ctx, name, args...)
40		out, err := cmd.Output()
41		if err != nil {
42			return nil, fmt.Errorf("%s %s: %w", name, strings.Join(args, " "), err)
43		}
44		return out, nil
45	}
46	
47	// parseDomifaddr extracts the first IPv4 address from `virsh domifaddr` output.
48	// Returns "" if no address is present yet.
49	func parseDomifaddr(out string) string {
50		for _, line := range strings.Split(out, "\n") {
51			fields := strings.Fields(line)
52			// Name MAC Protocol Address
53			if len(fields) < 4 {
54				continue
55			}
56			if strings.EqualFold(fields[2], "ipv4") {
57				addr := fields[3]
58				if i := strings.IndexByte(addr, '/'); i >= 0 {
59					addr = addr[:i]
60				}
61				return addr
62			}
63		}
64		return ""
65	}
66	
67	// domain is a name/state pair from `virsh list`.
68	type domain struct {
69		Name  string
70		State string
71	}
72	
73	// parseList parses `virsh list --all` into domains. The state column may contain
74	// spaces (e.g. "shut off").
75	func parseList(out string) []domain {
76		var domains []domain
77		lines := strings.Split(out, "\n")
78		for _, line := range lines {
79			trimmed := strings.TrimSpace(line)
80			if trimmed == "" {
81				continue
82			}
83			// Skip header and separator rows.
84			if strings.HasPrefix(trimmed, "Id") || strings.HasPrefix(trimmed, "---") {
85				continue
86			}
87			fields := strings.Fields(line)
88			// Id Name State... (Id may be "-")
89			if len(fields) < 3 {
90				continue
91			}
92			domains = append(domains, domain{
93				Name:  fields[1],
94				State: strings.Join(fields[2:], " "),
95			})
96		}
97		return domains
98	}
99	
100	// parseDominfoState extracts the State field from `virsh dominfo` output.
101	func parseDominfoState(out string) string {
102		for _, line := range strings.Split(out, "\n") {
103			if strings.HasPrefix(line, "State:") {
104				return strings.TrimSpace(strings.TrimPrefix(line, "State:"))
105			}
106		}
107		return ""
108	}
109	
110	// parseDomiflistMAC extracts the first interface MAC from `virsh domiflist`.
111	func parseDomiflistMAC(out string) string {
112		for _, line := range strings.Split(out, "\n") {
113			fields := strings.Fields(line)
114			if len(fields) < 5 {
115				continue
116			}
117			mac := fields[len(fields)-1]
118			if isMAC(mac) {
119				return mac
120			}
121		}
122		return ""
123	}
124	
125	// parseDnsmasqLease finds the IP leased to mac in a dnsmasq leases file.
126	func parseDnsmasqLease(content, mac string) string {
127		mac = strings.ToLower(mac)
128		for _, line := range strings.Split(content, "\n") {
129			fields := strings.Fields(line)
130			// timestamp MAC IP hostname clientid
131			if len(fields) < 3 {
132				continue
133			}
134			if strings.ToLower(fields[1]) == mac {
135				return fields[2]
136			}
137		}
138		return ""
139	}
140	
141	// isMAC reports whether s looks like aa:bb:cc:dd:ee:ff.
142	func isMAC(s string) bool {
143		parts := strings.Split(s, ":")
144		if len(parts) != 6 {
145			return false
146		}
147		for _, p := range parts {
148			if len(p) != 2 {
149				return false
150			}
151			for _, c := range p {
152				isHex := (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F')
153				if !isHex {
154					return false
155				}
156			}
157		}
158		return true
159	}
