19	// Provider is the AWS EC2 VMProvider implementation. It provisions an instance
20	// through a CloudFormation stack and manages Route53 DNS records.
21	type Provider struct {
22		// newClients constructs the AWS service clients for a region. It is a field
23		// so tests can inject fakes without network access.
24		newClients func(ctx context.Context, region string) (*clients, error)
25		StackPoll  stackPoll
26		Out        io.Writer
27	}
28	
29	// New returns a Provider that builds clients from the default AWS credential
30	// chain.
31	func New() *Provider {
32		return &Provider{
33			newClients: loadClients,
34			StackPoll:  defaultStackPoll,
35			Out:        os.Stderr,
36		}
37	}
38	
39	// Name implements provider.VMProvider.
40	func (p *Provider) Name() string { return "aws" }
41	
42	func (p *Provider) out() io.Writer {
43		if p.Out != nil {
44			return p.Out
45		}
46		return os.Stderr
47	}
