49	func (p *Provider) clients(ctx context.Context, region string) (*clients, error) {
50		if p.newClients == nil {
51			p.newClients = loadClients
52		}
53		if region == "" {
54			region = config.DefaultRegion
55		}
56		return p.newClients(ctx, region)
57	}
