59	// Create provisions the EC2 instance: AMI lookup, VPC/subnet discovery, a
60	// CloudFormation stack carrying the base64 cloud-init UserData, then DNS
61	// records. All outputs are written to cfg.AWS.
62	func (p *Provider) Create(ctx context.Context, cfg *config.Config, cloudInitPath string) error {
63		if cfg.VM == nil {
64			return fmt.Errorf("config missing vm section")
65		}
66		name := cfg.VM.Name
67		if err := config.ValidateName(name); err != nil {
68			return err
69		}
70	
71		userData, err := os.ReadFile(cloudInitPath)
72		if err != nil {
73			return fmt.Errorf("reading processed cloud-init: %w", err)
74		}
75		userDataB64 := base64.StdEncoding.EncodeToString(userData)
76	
77		cl, err := p.clients(ctx, cfg.VM.Region)
78		if err != nil {
79			return err
80		}
81	
82		amiID, err := lookupAMI(ctx, cl.ssm, cfg.VM.OS)
83		if err != nil {
84			return err
85		}
86	
87		net, err := ensureNetwork(ctx, cl.ec2, cfg.VM)
88		if err != nil {
89			return err
90		}
91	
92		body, err := renderTemplate(templateParams{
93			AMIID:        amiID,
94			InstanceType: cfg.VM.InstanceType,
95			SubnetID:     net.SubnetID,
96			VpcID:        net.VpcID,
97			UserDataB64:  userDataB64,
98			SSHCidr:      cfg.VM.SSHCidr,
99			WebCidr:      cfg.VM.WebCidr,
100		})
101		if err != nil {
102			return err
103		}
104	
105		stack := stackName(name)
106		stackID, outputs, err := createStack(ctx, cl.cfn, stack, body, p.StackPoll)
107		if err != nil {
108			return err
109		}
110	
111		cfg.AWS = &config.AWSState{
112			PublicIP:      outputs.PublicIP,
113			InstanceID:    outputs.InstanceID,
114			StackID:       stackID,
115			StackName:     stack,
116			SecurityGroup: outputs.SecurityGroupID,
117			AMIID:         amiID,
118		}
119		applyNetworkState(cfg.AWS, net)
120	
121		if err := createDNS(ctx, cl.route53, cfg, outputs.PublicIP); err != nil {
122			return err
123		}
124		return nil
125	}
126	
127	// Delete tears down DNS records, the CloudFormation stack, and any network
128	// resources govirt created, then clears cfg.AWS.
129	func (p *Provider) Delete(ctx context.Context, cfg *config.Config) error {
130		if cfg.AWS == nil {
131			return fmt.Errorf("VM not found: check 'govirt list' for available VMs")
132		}
133		if err := config.ValidateName(cfg.VM.Name); err != nil {
134			return err
135		}
136		cl, err := p.clients(ctx, cfg.VM.Region)
137		if err != nil {
138			return err
139		}
140	
141		if err := deleteDNS(ctx, cl.route53, cfg); err != nil {
142			fmt.Fprintf(p.out(), "warning: deleting DNS records: %v\n", err)
143		}
144		if cfg.AWS.StackName != "" {
145			if err := deleteStack(ctx, cl.cfn, cfg.AWS.StackName); err != nil {
146				return err
147			}
148		}
149		if err := cleanupNetwork(ctx, cl.ec2, cfg.AWS); err != nil {
150			fmt.Fprintf(p.out(), "warning: cleaning up network resources: %v\n", err)
151		}
152		cfg.AWS = nil
153		return nil
154	}
