156	// Status reports the EC2 instance state and current public IP.
157	func (p *Provider) Status(ctx context.Context, cfg *config.Config) (*provider.VMStatus, error) {
158		if cfg.AWS == nil || cfg.AWS.InstanceID == "" {
159			return nil, fmt.Errorf("VM not found: check 'govirt list' for available VMs")
160		}
161		cl, err := p.clients(ctx, cfg.VM.Region)
162		if err != nil {
163			return nil, err
164		}
165		inst, err := describeInstance(ctx, cl.ec2, cfg.AWS.InstanceID)
166		if err != nil {
167			return nil, err
168		}
169		state, ip, created := instanceStatus(inst)
170		return &provider.VMStatus{
171			Name:      cfg.VM.Name,
172			State:     state,
173			IP:        ip,
174			Provider:  p.Name(),
175			CreatedAt: created,
176		}, nil
177	}
