212	// Stop stops the instance (graceful guest shutdown).
213	func (p *Provider) Stop(ctx context.Context, cfg *config.Config) error {
214		id, cl, err := p.instanceAndClients(ctx, cfg)
215		if err != nil {
216			return err
217		}
218		if _, err := cl.ec2.StopInstances(ctx, &ec2.StopInstancesInput{InstanceIds: []string{id}}); err != nil {
219			return fmt.Errorf("stopping instance %s: %w", id, err)
220		}
221		return nil
222	}
223	
224	// Start starts the instance.
225	func (p *Provider) Start(ctx context.Context, cfg *config.Config) error {
226		id, cl, err := p.instanceAndClients(ctx, cfg)
227		if err != nil {
228			return err
229		}
230		if _, err := cl.ec2.StartInstances(ctx, &ec2.StartInstancesInput{InstanceIds: []string{id}}); err != nil {
231			return fmt.Errorf("starting instance %s: %w", id, err)
232		}
233		return nil
234	}
235	
236	// SSH replaces the current process with an interactive ssh session to the
237	// instance public IP, using the first configured user.
238	func (p *Provider) SSH(ctx context.Context, cfg *config.Config) error {
239		if cfg.AWS == nil || cfg.AWS.PublicIP == "" {
240			return fmt.Errorf("no public IP for %s: check 'govirt status %s'", cfg.VM.Name, cfg.VM.Name)
241		}
242		if len(cfg.VM.Users) == 0 {
243			return fmt.Errorf("no users defined for %s", cfg.VM.Name)
244		}
245		user := cfg.VM.Users[0].Username
246		sshPath, err := exec.LookPath("ssh")
247		if err != nil {
248			return fmt.Errorf("ssh not found: %w", err)
249		}
250		argv := []string{"ssh", "-o", "StrictHostKeyChecking=no", user + "@" + cfg.AWS.PublicIP}
251		return syscall.Exec(sshPath, argv, os.Environ())
252	}
253	
254	// SwapDNS implements provider.DNSSwapper: it points all tracked DNS records at
255	// the instance's current public IP, refreshing the IP from EC2 first.
256	func (p *Provider) SwapDNS(ctx context.Context, cfg *config.Config) error {
257		if cfg.AWS == nil || cfg.AWS.InstanceID == "" {
258			return fmt.Errorf("VM not found: check 'govirt list' for available VMs")
259		}
260		cl, err := p.clients(ctx, cfg.VM.Region)
261		if err != nil {
262			return err
263		}
264		inst, err := describeInstance(ctx, cl.ec2, cfg.AWS.InstanceID)
265		if err != nil {
266			return err
267		}
268		_, ip, _ := instanceStatus(inst)
269		if ip != "" {
270			cfg.AWS.PublicIP = ip
271		}
272		return swapDNS(ctx, cl.route53, cfg)
273	}
274	
275	// instanceAndClients resolves the instance ID and AWS clients for lifecycle
276	// operations.
277	func (p *Provider) instanceAndClients(ctx context.Context, cfg *config.Config) (string, *clients, error) {
278		if cfg.AWS == nil || cfg.AWS.InstanceID == "" {
279			return "", nil, fmt.Errorf("VM not found: check 'govirt list' for available VMs")
280		}
281		cl, err := p.clients(ctx, cfg.VM.Region)
282		if err != nil {
283			return "", nil, err
284		}
285		return cfg.AWS.InstanceID, cl, nil
286	}
287	
288	// instanceName returns the value of the instance's Name tag, falling back to its
289	// instance ID.
290	func instanceName(inst *ec2types.Instance) string {
291		for _, t := range inst.Tags {
292			if t.Key != nil && *t.Key == "Name" && t.Value != nil {
293				return *t.Value
294			}
295		}
296		if inst.InstanceId != nil {
297			return *inst.InstanceId
298		}
299		return ""
300	}
301	
302	var (
303		_ provider.VMProvider = (*Provider)(nil)
304		_ provider.DNSSwapper = (*Provider)(nil)
305	)
