1	package aws
2	
3	import (
4		"context"
5		"fmt"
6		"time"
7	
8		awssdk "github.com/aws/aws-sdk-go-v2/aws"
9		"github.com/aws/aws-sdk-go-v2/service/cloudformation"
10		cfntypes "github.com/aws/aws-sdk-go-v2/service/cloudformation/types"
11	)
12	
13	// stackPoll controls how long createStack waits for CREATE_COMPLETE.
14	type stackPoll struct {
15		interval time.Duration
16		timeout  time.Duration
17	}
18	
19	var defaultStackPoll = stackPoll{interval: 10 * time.Second, timeout: 15 * time.Minute}
20	
21	// stackOutputs holds the values parsed from a completed stack's outputs.
22	type stackOutputs struct {
23		InstanceID      string
24		PublicIP        string
25		SecurityGroupID string
26	}
27	
28	// createStack creates the CloudFormation stack, polls DescribeStacks until it
29	// reaches CREATE_COMPLETE, and returns the stack ID and parsed outputs. A
30	// terminal failure status (e.g. CREATE_FAILED, ROLLBACK_COMPLETE) is an error.
31	func createStack(ctx context.Context, api cfnAPI, name, templateBody string, poll stackPoll) (string, *stackOutputs, error) {
32		created, err := api.CreateStack(ctx, &cloudformation.CreateStackInput{
33			StackName:    awssdk.String(name),
34			TemplateBody: awssdk.String(templateBody),
35		})
36		if err != nil {
37			return "", nil, fmt.Errorf("creating stack %s: %w", name, err)
38		}
39		stackID := awssdk.ToString(created.StackId)
40	
41		deadline := time.Now().Add(poll.timeout)
42		for {
43			stack, err := describeStack(ctx, api, name)
44			if err != nil {
45				return stackID, nil, err
46			}
47			switch stack.StackStatus {
48			case cfntypes.StackStatusCreateComplete:
49				outputs := parseStackOutputs(stack.Outputs)
50				return stackID, outputs, nil
51			case cfntypes.StackStatusCreateInProgress:
52				// keep waiting
53			default:
54				return stackID, nil, fmt.Errorf("stack %s entered terminal state %s: %s",
55					name, stack.StackStatus, awssdk.ToString(stack.StackStatusReason))
56			}
57			if time.Now().After(deadline) {
58				return stackID, nil, fmt.Errorf("stack %s did not reach CREATE_COMPLETE within %s", name, poll.timeout)
59			}
60			select {
61			case <-ctx.Done():
62				return stackID, nil, ctx.Err()
63			case <-time.After(poll.interval):
64			}
65		}
66	}
67	
68	// describeStack returns the single stack matching name.
69	func describeStack(ctx context.Context, api cfnAPI, name string) (*cfntypes.Stack, error) {
70		out, err := api.DescribeStacks(ctx, &cloudformation.DescribeStacksInput{StackName: awssdk.String(name)})
71		if err != nil {
72			return nil, fmt.Errorf("describing stack %s: %w", name, err)
73		}
74		if len(out.Stacks) == 0 {
75			return nil, fmt.Errorf("stack %s not found", name)
76		}
77		return &out.Stacks[0], nil
78	}
79	
80	// parseStackOutputs extracts the InstanceId, PublicIP, and SecurityGroupId
81	// values from CloudFormation stack outputs.
82	func parseStackOutputs(outputs []cfntypes.Output) *stackOutputs {
83		result := &stackOutputs{}
84		for _, o := range outputs {
85			key := awssdk.ToString(o.OutputKey)
86			value := awssdk.ToString(o.OutputValue)
87			switch key {
88			case "InstanceId":
89				result.InstanceID = value
90			case "PublicIP":
91				result.PublicIP = value
92			case "SecurityGroupId":
93				result.SecurityGroupID = value
94			}
95		}
96		return result
97	}
