14	
15	// Provider is the DigitalOcean VMProvider implementation. The API is resolved
16	// lazily from the DIGITALOCEAN_TOKEN environment variable on first use so that
17	// constructing a Provider never requires a token; tests inject a fake API
18	// directly.
19	type Provider struct {
20		api  API
21		poll pollConfig
22		Out  io.Writer
23	}
24	
25	// New returns a Provider with production defaults. The DigitalOcean API client
26	// is built lazily on first use from the DIGITALOCEAN_TOKEN environment variable.
27	func New() *Provider {
28		return &Provider{
29			poll: defaultDropletPoll,
30			Out:  os.Stderr,
31		}
32	}
33	
34	// Name implements provider.VMProvider.
35	func (p *Provider) Name() string { return "do" }
36	
37	// ensureAPI lazily builds the godo-backed API from the environment if one has
38	// not been injected.
39	func (p *Provider) ensureAPI() error {
40		if p.api != nil {
41			return nil
42		}
43		api, err := newAPIFromEnv()
44		if err != nil {
45			return err
46		}
47		p.api = api
48		return nil
49	}
50	
51	// Create provisions a droplet, attaches a firewall, creates DNS records, and
52	// records the result in cfg.DO. The processed cloud-init document at
53	// cloudInitPath is passed as the droplet UserData.
54	func (p *Provider) Create(ctx context.Context, cfg *config.Config, cloudInitPath string) error {
55		if cfg.VM == nil {
56			return fmt.Errorf("config missing vm section")
57		}
58		if err := config.ValidateName(cfg.VM.Name); err != nil {
59			return err
60		}
61		if err := p.ensureAPI(); err != nil {
62			return err
63		}
64	
65		userData, err := os.ReadFile(cloudInitPath)
66		if err != nil {
67			return fmt.Errorf("reading processed cloud-init: %w", err)
68		}
69	
70		dropletID, ip, err := p.createDroplet(ctx, cfg, string(userData))
71		if err != nil {
72			return err
73		}
74	
75		firewallID, err := p.createFirewall(ctx, cfg, dropletID)
76		if err != nil {
77			return err
78		}
79	
80		records, err := p.createDNSRecords(ctx, cfg, ip)
81		if err != nil {
82			return err
83		}
84	
85		cfg.DO = &config.DOState{
86			DropletID:  dropletID,
87			PublicIP:   ip,
88			FirewallID: firewallID,
89			DNSRecords: records,
90		}
91		if cfg.DNS != nil {
92			cfg.DO.FQDN = cfg.DNS.Hostname + "." + cfg.DNS.Domain
93		}
94		return nil
95	}
96	
97	// Delete removes DNS records, the firewall, and the droplet, then clears cfg.DO.
98	func (p *Provider) Delete(ctx context.Context, cfg *config.Config) error {
99		if cfg.DO == nil {
100			return nil
101		}
102		if err := p.ensureAPI(); err != nil {
103			return err
104		}
105	
106		if err := p.deleteDNSRecords(ctx, cfg); err != nil {
107			return err
108		}
109		if cfg.DO.FirewallID != "" {
110			if _, err := p.api.Firewalls().Delete(ctx, cfg.DO.FirewallID); err != nil {
111				return fmt.Errorf("deleting firewall %s: %w", cfg.DO.FirewallID, err)
112			}
113		}
114		if cfg.DO.DropletID != 0 {
115			if _, err := p.api.Droplets().Delete(ctx, cfg.DO.DropletID); err != nil {
116				return fmt.Errorf("deleting droplet %d: %w", cfg.DO.DropletID, err)
117			}
118		}
119		cfg.DO = nil
120		return nil
121	}
122	
123	// Status reports the droplet state and current public IP.
124	func (p *Provider) Status(ctx context.Context, cfg *config.Config) (*provider.VMStatus, error) {
125		if cfg.DO == nil || cfg.DO.DropletID == 0 {
126			return nil, fmt.Errorf("VM not found: check 'govirt list --do' for available VMs")
127		}
128		if err := p.ensureAPI(); err != nil {
129			return nil, err
130		}
131		droplet, _, err := p.api.Droplets().Get(ctx, cfg.DO.DropletID)
132		if err != nil {
133			return nil, fmt.Errorf("getting droplet %d: %w", cfg.DO.DropletID, err)
134		}
135		ip, _ := droplet.PublicIPv4()
136		return &provider.VMStatus{
137			Name:     droplet.Name,
138			State:    droplet.Status,
139			IP:       ip,
140			Provider: p.Name(),
141		}, nil
142	}
143	
144	// List returns all droplets visible to the account.
145	func (p *Provider) List(ctx context.Context) ([]provider.VMStatus, error) {
146		if err := p.ensureAPI(); err != nil {
147			return nil, err
148		}
149		droplets, _, err := p.api.Droplets().List(ctx, nil)
150		if err != nil {
151			return nil, fmt.Errorf("listing droplets: %w", err)
152		}
153		var result []provider.VMStatus
154		for i := range droplets {
155			d := &droplets[i]
156			ip, _ := d.PublicIPv4()
157			result = append(result, provider.VMStatus{
158				Name:     d.Name,
159				State:    d.Status,
160				IP:       ip,
161				Provider: p.Name(),
162			})
163		}
164		return result, nil
165	}
166	
167	// Stop performs a graceful droplet shutdown.
168	func (p *Provider) Stop(ctx context.Context, cfg *config.Config) error {
169		if cfg.DO == nil || cfg.DO.DropletID == 0 {
170			return fmt.Errorf("VM not found: check 'govirt list --do' for available VMs")
171		}
172		if err := p.ensureAPI(); err != nil {
173			return err
174		}
175		if _, _, err := p.api.DropletActions().Shutdown(ctx, cfg.DO.DropletID); err != nil {
176			return fmt.Errorf("shutting down droplet %d: %w", cfg.DO.DropletID, err)
177		}
178		return nil
179	}
180	
181	// Start powers the droplet on.
182	func (p *Provider) Start(ctx context.Context, cfg *config.Config) error {
183		if cfg.DO == nil || cfg.DO.DropletID == 0 {
184			return fmt.Errorf("VM not found: check 'govirt list --do' for available VMs")
185		}
186		if err := p.ensureAPI(); err != nil {
187			return err
188		}
189		if _, _, err := p.api.DropletActions().PowerOn(ctx, cfg.DO.DropletID); err != nil {
190			return fmt.Errorf("powering on droplet %d: %w", cfg.DO.DropletID, err)
191		}
192		return nil
193	}
194	
195	// SSH replaces the current process with an interactive ssh session to the
196	// droplet's public IP, using the first configured user.
197	func (p *Provider) SSH(ctx context.Context, cfg *config.Config) error {
198		if cfg.VM == nil || len(cfg.VM.Users) == 0 {
199			return fmt.Errorf("no users defined")
200		}
201		if cfg.DO == nil || cfg.DO.PublicIP == "" {
202			return fmt.Errorf("no IP for %s: check 'govirt status %s --do'", cfg.VM.Name, cfg.VM.Name)
203		}
204		user := cfg.VM.Users[0].Username
205		sshPath, err := exec.LookPath("ssh")
206		if err != nil {
207			return fmt.Errorf("ssh not found: %w", err)
208		}
209		argv := []string{"ssh", "-o", "StrictHostKeyChecking=no", user + "@" + cfg.DO.PublicIP}
210		return syscall.Exec(sshPath, argv, os.Environ())
211	}
