1	package digitalocean
2	
3	import (
4		"context"
5		"fmt"
6		"time"
7	
8		"github.com/digitalocean/godo"
9		"github.com/gherlein/govirt/internal/config"
10	)
11	
12	// dropletPoll controls how long Create waits for a droplet to become active with
13	// an assigned public IP.
14	type pollConfig struct {
15		interval time.Duration
16		timeout  time.Duration
17	}
18	
19	var defaultDropletPoll = pollConfig{interval: 5 * time.Second, timeout: 5 * time.Minute}
20	
21	// buildDropletRequest maps the VM config and processed cloud-init document to a
22	// godo droplet create request. SSH keys are delivered via cloud-init UserData,
23	// not the godo SSHKeys field.
24	func buildDropletRequest(cfg *config.Config, userData string) *godo.DropletCreateRequest {
25		vm := cfg.VM
26		return &godo.DropletCreateRequest{
27			Name:   vm.Name,
28			Region: vm.DORegion,
29			Size:   vm.DOSize,
30			Image:  godo.DropletCreateImage{Slug: vm.DOImage},
31			// A public IP is required for SSH and DNS, so request public networking.
32			IPv6:     false,
33			UserData: userData,
34			VPCUUID:  vm.DOVpcID,
35			Tags:     []string{"govirt"},
36		}
37	}
38	
39	// createDroplet creates the droplet and polls until it is active with a public
40	// IP. It returns the droplet id and public IP.
41	func (p *Provider) createDroplet(ctx context.Context, cfg *config.Config, userData string) (int, string, error) {
42		req := buildDropletRequest(cfg, userData)
43		created, _, err := p.api.Droplets().Create(ctx, req)
44		if err != nil {
45			return 0, "", fmt.Errorf("creating droplet: %w", err)
46		}
47		id := created.ID
48	
49		ip, err := p.waitForActiveIP(ctx, id, p.poll)
50		if err != nil {
51			return id, "", err
52		}
53		return id, ip, nil
54	}
55	
56	// waitForActiveIP polls the droplet until it reports status "active" and has a
57	// public IPv4 address assigned.
58	func (p *Provider) waitForActiveIP(ctx context.Context, id int, poll pollConfig) (string, error) {
59		deadline := time.Now().Add(poll.timeout)
60		for {
61			droplet, _, err := p.api.Droplets().Get(ctx, id)
62			if err != nil {
63				return "", fmt.Errorf("polling droplet %d: %w", id, err)
64			}
65			if droplet.Status == "active" {
66				ip, err := droplet.PublicIPv4()
67				if err == nil && ip != "" {
68					return ip, nil
69				}
70			}
71			if time.Now().After(deadline) {
72				return "", fmt.Errorf("droplet %d not active with public IP after %s", id, poll.timeout)
73			}
74			select {
75			case <-ctx.Done():
76				return "", ctx.Err()
77			case <-time.After(poll.interval):
78			}
79		}
80	}
