275	func cmdDNS(ctx context.Context, args parsedArgs, folder string) error {
276		if args.subcommand != "swap" {
277			return fmt.Errorf("usage: govirt dns swap <name>")
278		}
279		cfg, cfgPath, err := loadStackConfig(args, folder)
280		if err != nil {
281			return err
282		}
283		providerName := selectProvider(args.provider, cfg)
284		if providerName == "local" {
285			return fmt.Errorf("dns swap is not available for local VMs")
286		}
287		p, err := buildProvider(providerName, args.verbose)
288		if err != nil {
289			return err
290		}
291		swapper, ok := p.(provider.DNSSwapper)
292		if !ok {
293			return fmt.Errorf("provider %q does not support dns swap", providerName)
294		}
295		if err := swapper.SwapDNS(ctx, cfg); err != nil {
296			return err
297		}
298		if err := config.Save(cfgPath, cfg); err != nil {
299			return err
300		}
301		fmt.Printf("swapped DNS for %s (%s)\n", args.name, providerName)
302		return nil
303	}
