3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"strings"
8	
9		"github.com/gherlein/govirt/internal/config"
10	)
11	
12	// parsedArgs is the result of parsing the command line.
13	type parsedArgs struct {
14		command    string // create|destroy|list|ssh|status|stop|start|dns
15		subcommand string // e.g. "swap" for "dns swap"
16		name       string
17		provider   string // "aws"|"do"|"local"|"" (auto-detect)
18		dir        string
19		folder     string
20		users      string
21		noHosts    bool
22		verbose    bool
23		version    bool
24		help       bool
25	}
26	
27	// parseArgs parses argv (excluding the program name). Flags may appear in any
28	// order and may be interspersed with positional arguments.
29	func parseArgs(argv []string) (parsedArgs, error) {
30		var a parsedArgs
31		var positionals []string
32	
33		for i := 0; i < len(argv); i++ {
34			arg := argv[i]
35			switch arg {
36			case "--aws":
37				a.provider = "aws"
38			case "--do", "--digitalocean":
39				a.provider = "do"
40			case "--local":
41				a.provider = "local"
42			case "--no-hosts":
43				a.noHosts = true
44			case "--verbose", "-v":
45				a.verbose = true
46			case "--version":
47				a.version = true
48			case "--help", "-h":
49				a.help = true
50			case "--dir":
51				val, err := nextValue(argv, &i, arg)
52				if err != nil {
53					return a, err
54				}
55				a.dir = val
56			case "--folder", "-f":
57				val, err := nextValue(argv, &i, arg)
58				if err != nil {
59					return a, err
60				}
61				a.folder = val
62			case "--users", "-u":
63				val, err := nextValue(argv, &i, arg)
64				if err != nil {
65					return a, err
66				}
67				a.users = val
68			default:
69				if strings.HasPrefix(arg, "-") {
70					return a, fmt.Errorf("unknown flag: %s", arg)
71				}
72				positionals = append(positionals, arg)
73			}
74		}
75	
76		if len(positionals) > 0 {
77			a.command = positionals[0]
78		}
79		if a.command == "dns" {
80			if len(positionals) > 1 {
81				a.subcommand = positionals[1]
82			}
83			if len(positionals) > 2 {
84				a.name = positionals[2]
85			}
86		} else if len(positionals) > 1 {
87			a.name = positionals[1]
88		}
89		return a, nil
90	}
91	
92	// nextValue consumes the value following a flag that requires one.
93	func nextValue(argv []string, i *int, flag string) (string, error) {
94		if *i+1 >= len(argv) {
95			return "", fmt.Errorf("flag %s requires a value", flag)
96		}
97		*i++
98		return argv[*i], nil
99	}
100	
101	// resolveStackFolder applies the documented precedence:
102	// --folder > --dir/stacks > GOVIRT_STACK_FOLDER > ~/.config/govirt/stacks.
103	func resolveStackFolder(folder, dir, envFolder, home string) string {
104		if folder != "" {
105			return folder
106		}
107		if dir != "" {
108			return filepath.Join(dir, "stacks")
109		}
110		if envFolder != "" {
111			return envFolder
112		}
113		return filepath.Join(home, ".config", "govirt", "stacks")
114	}
115	
116	// selectProvider returns the provider name from an explicit flag, or applies
117	// auto-detection from existing state sections.
118	func selectProvider(flag string, cfg *config.Config) string {
119		if flag != "" {
120			return flag
121		}
122		if cfg.DO != nil && cfg.Local == nil {
123			return "do"
124		}
125		if cfg.AWS != nil && cfg.Local == nil {
126			return "aws"
127		}
128		return "local"
129	}
130	
131	// parseUsersOverride maps a comma-separated GitHub username list to VM users.
132	// The first username becomes the "ubuntu" account; the rest map username ==
133	// github_username.
134	func parseUsersOverride(spec string) []config.User {
135		parts := strings.Split(spec, ",")
136		var users []config.User
137		for i, p := range parts {
138			name := strings.TrimSpace(p)
139			if name == "" {
140				continue
141			}
142			if i == 0 {
143				users = append(users, config.User{Username: "ubuntu", GitHubUsername: name})
144			} else {
145				users = append(users, config.User{Username: name, GitHubUsername: name})
146			}
147		}
148		return users
149	}
150	
151	// homeDir returns the user's home directory, falling back to "" on error.
152	func homeDir() string {
153		h, err := os.UserHomeDir()
154		if err != nil {
155			return ""
156		}
157		return h
158	}
