26	func (f *fakeDroplets) Create(ctx context.Context, req *godo.DropletCreateRequest) (*godo.Droplet, *godo.Response, error) {
27		f.created = req
28		if f.err != nil {
29			return nil, nil, f.err
30		}
31		return f.createResult, nil, nil
32	}
33	
34	func (f *fakeDroplets) Get(ctx context.Context, id int) (*godo.Droplet, *godo.Response, error) {
35		if f.err != nil {
36			return nil, nil, f.err
37		}
38		i := f.getCalls
39		if i >= len(f.getResults) {
40			i = len(f.getResults) - 1
41		}
42		f.getCalls++
43		return f.getResults[i], nil, nil
44	}
