191					Region:   "nyc3",
192					Size:     "s-2vcpu-4gb",
193					Image:    godo.DropletCreateImage{Slug: "ubuntu-24-04-x64"},
194					UserData: "#cloud-config\n",
195					Tags:     []string{"govirt"},
196				},
197			},
198			{
199				name: "vpc set",
200				mutate: func(c *config.Config) {
201					c.VM.DOVpcID = "vpc-uuid-123"
202				},
203				userData: "data",
204				want: godo.DropletCreateRequest{
205					Name:     "web",
206					Region:   "nyc3",
207					Size:     "s-2vcpu-4gb",
208					Image:    godo.DropletCreateImage{Slug: "ubuntu-24-04-x64"},
209					UserData: "data",
210					VPCUUID:  "vpc-uuid-123",
211					Tags:     []string{"govirt"},
212				},
213			},
214		}
215		for _, tt := range tests {
216			t.Run(tt.name, func(t *testing.T) {
217				cfg := baseConfig()
218				if tt.mutate != nil {
219					tt.mutate(cfg)
220				}
221				got := buildDropletRequest(cfg, tt.userData)
222				if got.Name != tt.want.Name || got.Region != tt.want.Region ||
223					got.Size != tt.want.Size || got.Image.Slug != tt.want.Image.Slug ||
224					got.UserData != tt.want.UserData || got.VPCUUID != tt.want.VPCUUID {
225					t.Errorf("buildDropletRequest() = %+v, want %+v", got, tt.want)
226				}
227				if len(got.Tags) != 1 || got.Tags[0] != "govirt" {
228					t.Errorf("Tags = %v, want [govirt]", got.Tags)
229				}
230			})
231		}
