234	func TestBuildFirewallRequest(t *testing.T) {
235		tests := []struct {
236			name       string
237			sshCIDR    string
238			webCIDR    string
239			wantSSHSrc string
240			wantWebSrc string
241		}{
242			{name: "defaults", sshCIDR: "", webCIDR: "", wantSSHSrc: DefaultCIDR, wantWebSrc: DefaultCIDR},
243			{name: "custom cidrs", sshCIDR: "10.0.0.0/8", webCIDR: "192.168.0.0/16", wantSSHSrc: "10.0.0.0/8", wantWebSrc: "192.168.0.0/16"},
244		}
245		for _, tt := range tests {
246			t.Run(tt.name, func(t *testing.T) {
247				cfg := baseConfig()
248				cfg.VM.SSHCidr = tt.sshCIDR
249				cfg.VM.WebCidr = tt.webCIDR
250				got := buildFirewallRequest(cfg, 42)
251	
252				if got.Name != "govirt-web" {
253					t.Errorf("Name = %q, want govirt-web", got.Name)
254				}
255				if len(got.DropletIDs) != 1 || got.DropletIDs[0] != 42 {
256					t.Errorf("DropletIDs = %v, want [42]", got.DropletIDs)
257				}
258				if len(got.InboundRules) != 3 {
259					t.Fatalf("got %d inbound rules, want 3", len(got.InboundRules))
260				}
261				wantPorts := map[string]string{"22": tt.wantSSHSrc, "80": tt.wantWebSrc, "443": tt.wantWebSrc}
262				for _, rule := range got.InboundRules {
263					if rule.Protocol != "tcp" {
264						t.Errorf("port %s protocol = %q, want tcp", rule.PortRange, rule.Protocol)
265					}
266					wantSrc, ok := wantPorts[rule.PortRange]
267					if !ok {
268						t.Errorf("unexpected port %q", rule.PortRange)
269						continue
270					}
271					if rule.Sources == nil || len(rule.Sources.Addresses) != 1 || rule.Sources.Addresses[0] != wantSrc {
272						t.Errorf("port %s sources = %+v, want %q", rule.PortRange, rule.Sources, wantSrc)
273					}
274					delete(wantPorts, rule.PortRange)
275				}
276				if len(wantPorts) != 0 {
277					t.Errorf("missing ports: %v", wantPorts)
278				}
279			})
280		}
281	}
