283	func TestPlanDNSRecords(t *testing.T) {
284		tests := []struct {
285			name string
286			dns  *config.DNSConfig
287			want []godo.DomainRecordEditRequest
288		}{
289			{name: "nil dns yields none", dns: nil, want: nil},
290			{
291				name: "hostname A only",
292				dns:  &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300},
293				want: []godo.DomainRecordEditRequest{
294					{Type: "A", Name: "web", Data: "1.2.3.4", TTL: 300},
295				},
296			},
297			{
298				name: "apex adds @ record",
299				dns:  &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300, IsApexDomain: true},
300				want: []godo.DomainRecordEditRequest{
301					{Type: "A", Name: "web", Data: "1.2.3.4", TTL: 300},
302					{Type: "A", Name: "@", Data: "1.2.3.4", TTL: 300},
303				},
304			},
305			{
306				name: "cname aliases point at hostname fqdn",
307				dns:  &config.DNSConfig{Hostname: "web", Domain: "example.com", TTL: 300, CNAMEAliases: []string{"www"}},
308				want: []godo.DomainRecordEditRequest{
309					{Type: "A", Name: "web", Data: "1.2.3.4", TTL: 300},
310					{Type: "CNAME", Name: "www", Data: "web.example.com.", TTL: 300},
311				},
312			},
313		}
314		for _, tt := range tests {
315			t.Run(tt.name, func(t *testing.T) {
316				cfg := baseConfig()
317				cfg.DNS = tt.dns
318				got := planDNSRecords(cfg, "1.2.3.4")
319				if len(got) != len(tt.want) {
320					t.Fatalf("got %d records, want %d", len(got), len(tt.want))
321				}
322				for i, w := range tt.want {
323					g := got[i]
324					if g.Type != w.Type || g.Name != w.Name || g.Data != w.Data || g.TTL != w.TTL {
325						t.Errorf("record[%d] = %+v, want %+v", i, *g, w)
326					}
327				}
328			})
329		}
330	}
